public class CoinChange {

    public int minCoins(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1); // initialize to a large value ("infinity")
        dp[0] = 0;
        // TODO: for each amount from 1 to amount:
        //       for each coin: if coin <= amt and dp[amt-coin]+1 < dp[amt], update dp[amt]
        return dp[amount] > amount ? -1 : dp[amount];
    }

    public static void main(String[] args) {
        CoinChange cc = new CoinChange();
        System.out.println("Coins [1,2,5], amount=11: " + cc.minCoins(new int[]{1,2,5}, 11));
        System.out.println("Coins [2],      amount=3:  " + cc.minCoins(new int[]{2}, 3));
        System.out.println("Coins [1,5,10], amount=18: " + cc.minCoins(new int[]{1,5,10}, 18));
        System.out.println("Coins [2,5,10], amount=3:  " + cc.minCoins(new int[]{2,5,10}, 3));
    }
}

